SELECT MAX(max_temp_f) 
FROM temperature_data 
WHERE location_id = 1 AND date BETWEEN '2023-01-01' AND '2023-12-31';

SELECT MAX(max_temp_f) AS MaxTemperature
FROM weather_data
WHERE date = '2022-06-01';

SELECT MAX(max_temp_f) 
FROM temperature_data 
WHERE date = '2022-01-01' AND location_id = 1;

SELECT max_temp_f, mean_temp_f, min_temp_f
FROM temperature_data
WHERE location_id = 0 AND date = '2022-09-01';

SELECT date
FROM precipitation_data
WHERE location_id = 1;

SELECT users.user_name
FROM users
JOIN data_export ON users.user_id = data_export.user_id;

SELECT date, max_temp_f, mean_temp_f, min_temp_f 
FROM temperature_data 
ORDER BY date DESC;

SELECT max_temp_f
FROM weather_data
WHERE date = '2022-01-01';

SELECT COUNT(DISTINCT dataset_ratings.user_id) 
FROM dataset_ratings 
WHERE dataset_ratings.rating_value > 3;

SELECT max_humidity, mean_humidity, min_humidity
FROM humidity_data
WHERE date = 'desired_date' AND location_id = 'desired_location_id';
